from enum import Enum
import anthropic

client = anthropic.Anthropic()

class Phase(str, Enum):
    RESEARCH  = "research"
    PLAN      = "plan"
    IMPLEMENT = "implement"
    REVIEW    = "review"

# Tool definitions (abbreviated)
web_search_tool  = {"name": "web_search",   "description": "Search the web.", "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}}
read_file_tool   = {"name": "read_file",    "description": "Read a file.",    "input_schema": {"type": "object", "properties": {"path":  {"type": "string"}}, "required": ["path"]}}
write_file_tool  = {"name": "write_file",   "description": "Write a file.",   "input_schema": {"type": "object", "properties": {"path":  {"type": "string"}, "content": {"type": "string"}}, "required": ["path", "content"]}}
run_tests_tool   = {"name": "run_tests",    "description": "Run test suite.", "input_schema": {"type": "object", "properties": {"path":  {"type": "string"}}, "required": ["path"]}}
lint_tool        = {"name": "lint",         "description": "Lint code.",      "input_schema": {"type": "object", "properties": {"path":  {"type": "string"}}, "required": ["path"]}}

TOOLS_BY_PHASE: dict[Phase, list[dict]] = {
    Phase.RESEARCH:  [web_search_tool, read_file_tool],
    Phase.PLAN:      [read_file_tool],
    Phase.IMPLEMENT: [read_file_tool, write_file_tool],
    Phase.REVIEW:    [read_file_tool, run_tests_tool, lint_tool],
}

def run_phase(messages: list, phase: Phase, max_turns: int = 10) -> list:
    """Run one phase of the agent, returning updated messages."""
    tools = TOOLS_BY_PHASE[phase]

    for _ in range(max_turns):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=tools,
            tool_choice={"type": "auto"},
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            break

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                result = dispatch_tool(block.name, block.input)
                tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": tool_results})

    return messages

# Orchestrate phases
messages = [{"role": "user", "content": "Implement a CSV parser in Python."}]
for phase in [Phase.RESEARCH, Phase.PLAN, Phase.IMPLEMENT, Phase.REVIEW]:
    messages.append({"role": "user", "content": f"Now proceed with the {phase.value} phase."})
    messages = run_phase(messages, phase)

def run_agent_with_use_tracking(user_message: str, all_tools: list) -> str:
    messages = [{"role": "user", "content": user_message}]
    available_tools = list(all_tools)          # mutable copy
    used_tools: set[str] = set()

    SINGLE_USE = {"send_email", "create_ticket", "initialize_session"}

    for _ in range(15):
        response = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=4096,
            tools=available_tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b, "text"))

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            result = dispatch_tool(block.name, block.input)
            tool_results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})

            # Retire single-use tools after first invocation
            if block.name in SINGLE_USE and block.name not in used_tools:
                used_tools.add(block.name)
                available_tools = [t for t in available_tools if t["name"] != block.name]

        messages.append({"role": "user", "content": tool_results})

    raise RuntimeError("Max turns exceeded")
